import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, StatusCodes}
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import akka.stream.ActorMaterializer
import scala.concurrent.Future
import java.net.{InetAddress, URI}

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy-system")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  val allowedHosts = Set("example.com", "api.partner.com")

  def isValidUrl(url: String): Boolean = {
    try {
      val uri = new URI(url)
      val host = uri.getHost
      val ip = InetAddress.getByName(host)

      !ip.isLoopbackAddress &&
      !ip.isLinkLocalAddress &&
      !ip.isMulticastAddress &&
      !ip.isSiteLocalAddress &&
      allowedHosts.contains(host)
    } catch {
      case _: Exception => false
    }
  }

  def fetchContent(url: String): Future[String] = {
    if (isValidUrl(url)) {
      val request = HttpRequest(uri = url)
      Http().singleRequest(request).flatMap { response =>
        response.entity.toStrict(3000.millis).map(_.data.utf8String)
      }
    } else {
      Future.failed(new IllegalArgumentException("Invalid URL"))
    }
  }

  val route: Route =
    path("fetch") {
      post {
        entity(as[String]) { url =>
          onComplete(fetchContent(url)) {
            case scala.util.Success(content) => complete(content)
            case scala.util.Failure(ex) => complete(StatusCodes.BadRequest, ex.getMessage)
          }
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
}